--
-- Table structure for table `routes`
--

DROP TABLE IF EXISTS `routes`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `routes` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `route_id` varchar(20) NOT NULL,
  `name` varchar(255) NOT NULL,
  `name_short` varchar(100) DEFAULT NULL,
  `region` varchar(50) NOT NULL,
  `type` varchar(50) NOT NULL,
  `duration_days` int(11) NOT NULL,
  `budget_per_day` int(11) NOT NULL,
  `difficulty` int(11) NOT NULL,
  `rating` float NOT NULL DEFAULT 0,
  `season` varchar(50) NOT NULL,
  `transport` varchar(50) NOT NULL,
  `group_type` varchar(50) NOT NULL,
  `description` text DEFAULT NULL,
  `long_description` text DEFAULT NULL,
  `nature_score` int(11) NOT NULL DEFAULT 1,
  `culture_score` int(11) NOT NULL DEFAULT 1,
  `comfort_score` int(11) NOT NULL DEFAULT 1,
  `adventure_score` int(11) NOT NULL DEFAULT 1,
  `cost_score` int(11) NOT NULL DEFAULT 1,
  `profile_match` varchar(50) DEFAULT NULL,
  `image_url` varchar(255) DEFAULT NULL,
  `object_ids` text DEFAULT NULL,
  `start_lat` float DEFAULT NULL,
  `start_lng` float DEFAULT NULL,
  `path_coords` text DEFAULT NULL,
  `day_markers` text DEFAULT NULL,
  `featured` int(11) NOT NULL DEFAULT 0,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `routes_route_id_unique` (`route_id`)
) ENGINE=InnoDB AUTO_INCREMENT=95 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

